import{f as e,o as r,c as t,a7 as a}from"./chunks/framework.CE9Fg-de.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段11-日志监控与可观测性.md","filePath":"S6-Go/阶段11-日志监控与可观测性.md","lastUpdated":1780493670000}'),n={name:"S6-Go/阶段11-日志监控与可观测性.md"};function s(g,o,l,c,d,i){return r(),t("div",null,[...o[0]||(o[0]=[a('<h2 id="📊-阶段十一-日志、监控与可观测性" tabindex="-1">📊 阶段十一：日志、监控与可观测性 <a class="header-anchor" href="#📊-阶段十一-日志、监控与可观测性" aria-label="Permalink to &quot;📊 阶段十一：日志、监控与可观测性&quot;">​</a></h2><h3 id="_11-1-日志规范" tabindex="-1">11.1 日志规范 <a class="header-anchor" href="#_11-1-日志规范" aria-label="Permalink to &quot;11.1 日志规范&quot;">​</a></h3><h4 id="q47-生产环境日志应该如何设计-结构化日志的优势" tabindex="-1">Q47: 生产环境日志应该如何设计？结构化日志的优势？ <a class="header-anchor" href="#q47-生产环境日志应该如何设计-结构化日志的优势" aria-label="Permalink to &quot;Q47: 生产环境日志应该如何设计？结构化日志的优势？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：日志级别、JSON 格式、TraceID 关联、<code>zap</code>/<code>logrus</code>。</p><p><strong>💡 记忆关键词</strong>：JSON 格式、TraceID、日志级别、zap</p><p><strong>答案要点</strong>：</p><ul><li><strong>级别</strong>：DEBUG（开发）、INFO（关键流程）、WARN（可恢复异常）、ERROR（需人工介入）、FATAL（进程退出）。</li><li><strong>结构化</strong>：使用 JSON 格式，便于 ELK/Loki 解析和聚合查询。</li><li><strong>链路追踪</strong>：每条日志必须携带 <code>TraceID</code> 和 <code>SpanID</code>，通过 <code>context</code> 传递。</li><li><strong>性能</strong>：使用 <code>uber-go/zap</code>（零分配序列化）替代 <code>log</code>，避免日志成为性能瓶颈。</li></ul><h3 id="_11-2-指标监控" tabindex="-1">11.2 指标监控 <a class="header-anchor" href="#_11-2-指标监控" aria-label="Permalink to &quot;11.2 指标监控&quot;">​</a></h3><h4 id="q48-如何使用-prometheus-grafana-监控-go-服务" tabindex="-1">Q48: 如何使用 Prometheus + Grafana 监控 Go 服务？ <a class="header-anchor" href="#q48-如何使用-prometheus-grafana-监控-go-服务" aria-label="Permalink to &quot;Q48: 如何使用 Prometheus + Grafana 监控 Go 服务？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：Metrics 类型、<code>prometheus/client_golang</code>、P99 延迟、自定义指标。</p><p><strong>💡 记忆关键词</strong>：Counter/Gauge/Histogram/Summary、P99 延迟、Alertmanager</p><p><strong>答案要点</strong>：</p><ul><li><strong>四大指标</strong>：Counter（累加）、Gauge（瞬时值）、Histogram（分布统计）、Summary（分位数）。</li><li><strong>Go 运行时指标</strong>：官方库默认暴露 <code>go_goroutines</code>、<code>go_gc_duration_seconds</code>、<code>go_memstats_*</code> 等。</li><li><strong>业务指标</strong>：QPS、错误率、接口 P99 延迟、DB 连接池使用率、缓存命中率。</li><li><strong>告警</strong>：配置 Alertmanager，规则如 <code>http_request_duration_seconds{quantile=&quot;0.99&quot;} &gt; 1s</code>。</li></ul><h4 id="q49-什么是-opentelemetry-go-中如何集成" tabindex="-1">Q49: 什么是 OpenTelemetry？Go 中如何集成？ <a class="header-anchor" href="#q49-什么是-opentelemetry-go-中如何集成" aria-label="Permalink to &quot;Q49: 什么是 OpenTelemetry？Go 中如何集成？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：Trace/Metric/Log 统一标准、自动插桩、导出器。</p><p><strong>💡 记忆关键词</strong>：Trace/Metric/Log 统一、自动插桩、Exporter</p><p><strong>答案要点</strong>：</p><ul><li>OpenTelemetry (OTel) 是 CNCF 可观测性标准，统一 Tracing、Metrics、Logs 的采集与导出。</li><li><strong>Go 集成</strong>：使用 <code>go.opentelemetry.io/otel</code>，配置 <code>TracerProvider</code> 和 <code>Exporter</code>（如 Jaeger、Tempo）。</li><li><strong>自动插桩</strong>：配合 <code>otelhttp</code>、<code>otelgrpc</code>、<code>otelsql</code> 自动捕获 HTTP/gRPC/DB 调用链，无需手动埋点。</li></ul><hr>',22)])])}const u=e(n,[["render",s]]);export{_ as __pageData,u as default};
